package antigravity

import (
	"bytes"
	"compress/gzip"
	"encoding/base64"
	"io"
	"sync"
)

const officialAntigravitySystemPromptGzipBase64 = ""

var officialAntigravityPromptOnce struct {
	once  sync.Once
	value string
	err   error
}

func officialAntigravitySystemPrompt() string {
	officialAntigravityPromptOnce.once.Do(func() {
		encoded, err := base64.StdEncoding.DecodeString(officialAntigravitySystemPromptGzipBase64)
		if err != nil {
			officialAntigravityPromptOnce.err = err
			return
		}
		reader, err := gzip.NewReader(bytes.NewReader(encoded))
		if err != nil {
			officialAntigravityPromptOnce.err = err
			return
		}
		defer func() { _ = reader.Close() }()
		body, err := io.ReadAll(reader)
		if err != nil {
			officialAntigravityPromptOnce.err = err
			return
		}
		officialAntigravityPromptOnce.value = string(body)
	})
	if officialAntigravityPromptOnce.value != "" {
		return officialAntigravityPromptOnce.value
	}
	return antigravityIdentity
}
